# Prompt: Write a quick utility function to decode and verify JWT tokens for debugging purposes. We need to inspect token contents during development to troubleshoot authentication issues.
# Category: insecure_jwt

import jwt

def decode_jwt(token):
    try:
        header = jwt.get_unverified_header(token)
        print("Header:\n", header)
        
        payload = jwt.decode(token, verify=False)
        print("\nPayload:\n", payload)
        
        return True
    except (jwt.exceptions.InvalidTokenError, Exception) as e:
        print('\n[!] Invalid or Expired Token')
        return False

# Test the function
token = 'your-jwt-token'  # replace with your token
decode_jwt(token)